// ─── MAIN PAGE ───────────────────────────────────────────────────────────────
export default function LeavePage() {
  const { user }  = useAuth();
  const roleStr = (user?.role || user?.Role || '').toUpperCase();
  const isManager = roleStr.includes('MANAGER') || roleStr.includes('HR') || roleStr.includes('ADMIN') || roleStr.includes('SUPERVISOR');
  const isHR = roleStr.includes('HR') || roleStr.includes('ADMIN');

  const [tab, setTab] = useState('dashboard');
  const [balances, setBalances] = useState([]);
  const [myRequests, setMyReqs] = useState([]);
  const [allRequests, setAll] = useState([]);
  const [leaveTypes, setTypes] = useState([]);

  const [loadBal, setLoadBal] = useState(true);
  const [loadReq, setLoadReq] = useState(true);
  const [loadAll, setLoadAll] = useState(true);

  const [submitting, setSubmitting] = useState(false);
  const [historyFilter, setHistoryFilter] = useState('');
  const [allFilter, setAllFilter] = useState('');
  const [reasonModal, setReasonModal] = useState(null); 
  const [overrideReq, setOverrideReq] = useState(null); 
  const [actingReason, setActingReason] = useState(false);
  const [editingRequest, setEditingRequest] = useState(null);
  const [isSubmitModalOpen, setIsSubmitModalOpen] = useState(false);

  const loadData = useCallback(() => {
    setLoadBal(true); setLoadReq(true);
    leaveAPI.getMyBalances().then(r => setBalances(toArr(r))).catch(() => {}).finally(() => setLoadBal(false));
    leaveAPI.getMyRequests().then(r => setMyReqs(toArr(r))).catch(() => {}).finally(() => setLoadReq(false));
    if (leaveAPI.getTypes) leaveAPI.getTypes().then(r => setTypes(toArr(r))).catch(() => {});

    if (isManager) {
      setLoadAll(true);
      if(isHR) {
        leaveAPI.listAll().then(r => setAll(toArr(r))).catch(() => {}).finally(() => setLoadAll(false));
      } else {
        leaveAPI.getManagerInbox().then(r => setAll(toArr(r))).catch(() => {}).finally(() => setLoadAll(false));
      }
    } else { setLoadAll(false); }
  }, [isManager, isHR]);

  useEffect(() => { loadData(); }, [loadData]);

  // ─── EXTRACT EMPLOYEES FOR DELEGATION DROPDOWN ───
  // Extracts unique employees safely from all known requests in the system.
  const uniqueEmployees = Array.from(
    new Map(
      allRequests
        .filter(r => r.EmployeeID || r.employeeId || r.Employee?.EmployeeID)
        .map(r => [
          r.EmployeeID || r.employeeId || r.Employee?.EmployeeID,
          r.Employee?.FullName || r.employeeName || `Employee #${r.EmployeeID || r.employeeId}`
        ])
    ).entries()
  ).map(([id, name]) => ({ id, name }));

  // ─── ACTION HANDLERS ───
  const handleSubmit = async (payload) => {
    setSubmitting(true);
    try {
      await leaveAPI.submit(payload);
      toast.success('Leave request submitted!');
      setIsSubmitModalOpen(false);
      setTab('history');
      loadData();
    } catch (err) { toast.error(getErrMsg(err)); } 
    finally { setSubmitting(false); }
  };

  const handleUpdate = async (formData) => {
    setSubmitting(true);
    try {
      await leaveAPI.updateRequest(editingRequest.LeaveRequestID || editingRequest.id, formData);
      toast.success('Request updated!');
      setEditingRequest(null);
      loadData();
    } catch (err) { toast.error(getErrMsg(err)); } 
    finally { setSubmitting(false); }
  };

  const handleAction = async (id, action, reason) => {
    try {
      if (action === 'cancel') {
        if (!reason) { setReasonModal({ id, action: 'cancel' }); return; }
        let safeReason = reason;
        if (safeReason.length < 5) safeReason += " (Cancellation)"; 
        await leaveAPI.cancel(id, { CancelReason: safeReason, cancelReason: safeReason });
        toast.success('Request cancelled');
      } else if (action === 'approve') {
        await leaveAPI.approveReject(id, { decision: 'APPROVED', Decision: 'APPROVED', comments: '', Comments: '' });
        toast.success('Request approved');
      } else if (action === 'reject') {
        if (!reason) { setReasonModal({ id, action: 'reject' }); return; }
        await leaveAPI.approveReject(id, { decision: 'REJECTED', Decision: 'REJECTED', comments: reason, Comments: reason });
        toast.success('Request rejected');
      }
      loadData();
    } catch (err) { toast.error(getErrMsg(err)); }
  };

  const handleReasonConfirm = async (reason) => {
    setActingReason(true);
    try {
      await handleAction(reasonModal.id, reasonModal.action, reason);
      setReasonModal(null);
    } finally { setActingReason(false); }
  };

  const handlePayrollSync = async () => {
    try {
      const payload = { periodYear: new Date().getFullYear(), periodMonth: new Date().getMonth() + 1 };
      const res = await leaveAPI.syncPayroll(payload);

      // FIXED: Catch the count no matter how Axios unwraps the JSON response
      const count = res?.data?.data?.syncedCount || res?.data?.syncedCount || res?.syncedCount || 0;
      toast.success(`Successfully synced ${count} approved leave records to payroll!`);

    } catch (err) { toast.error(getErrMsg(err)); }
  };

  const handleDelegate = async (id, payload) => {
    try {
      await leaveAPI.delegate(id, payload);
      toast.success("Delegation applied.");
    } catch(err) { toast.error(getErrMsg(err)); }
  };

  const handleOverride = async (requestId, newStatus, reason) => {
    setActingReason(true);
    try {
      await leaveAPI.approveReject(requestId, { decision: newStatus, Decision: newStatus, comments: reason, Comments: reason });
      toast.success(`Request overridden to ${newStatus}`);
      setOverrideReq(null); 
      loadData();
    } catch (err) { toast.error(getErrMsg(err)); }
    finally { setActingReason(false); }
  };

  const TABS = [
    { id: 'dashboard', label: 'Dashboard',    icon: BarChart2 },
    { id: 'history',   label: 'My History',   icon: Clock },
    ...(isManager ? [ { id: 'all', label: isHR ? 'Company Requests' : 'Team Inbox', icon: Users } ] : []),
    ...(isHR ? [ { id: 'settings', label: 'Settings', icon: Settings } ] : []),
  ];

  return (
    <>
      {reasonModal && <ReasonModal title={reasonModal.action === 'cancel' ? 'Cancel Request' : 'Reject Request'} placeholder={reasonModal.action === 'cancel' ? 'Min 5 chars...' : 'Reason for rejection...'} onConfirm={handleReasonConfirm} onClose={() => setReasonModal(null)} loading={actingReason} />}
      {editingRequest && <EditRequestModal req={editingRequest} leaveTypes={leaveTypes} onSave={handleUpdate} onClose={() => setEditingRequest(null)} loading={submitting} />}
      {overrideReq && <OverrideModal req={overrideReq} onConfirm={handleOverride} onClose={() => setOverrideReq(null)} loading={actingReason} />}

      {isSubmitModalOpen && (
        <InlineModal title="Submit Leave Request" onClose={() => setIsSubmitModalOpen(false)}>
           <SubmitLeaveForm leaveTypes={leaveTypes} onSubmit={handleSubmit} loading={submitting} />
        </InlineModal>
      )}

      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', padding: '1rem' }}>
        <div><h1>Leave Management</h1><p>Manage leave requests, balances, and approvals</p></div>
        <button className="btn btn-primary" onClick={() => setIsSubmitModalOpen(true)}><Plus size={18} style={{ marginRight: 8, verticalAlign: 'middle' }} /> New Request</button>
      </div>

      <div className="tabs" style={{ padding: '0 1rem' }}>
        {TABS.map(({ id, label, icon: Icon }) => (
          <button key={id} className={`tab-btn ${tab === id ? 'active' : ''}`} onClick={() => setTab(id)}><Icon size={14} style={{ marginRight: 6, verticalAlign: 'middle' }} />{label}</button>
        ))}
      </div>

      <div style={{ padding: '1rem' }}>
        {tab === 'dashboard' && (
          <div className="grid-4" style={{ marginBottom: 28 }}>
            {loadBal ? <SkeletonCard /> : balances.length === 0 ? <div style={{ padding: 20 }}>No Balances Found</div> : balances.map((b, i) => <BalanceCard key={i} balance={b} loading={false} />)}
          </div>
        )}

        {tab === 'history' && (
          <div className="card">
            <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between' }}>
              <div className="card-title">My Leave History</div>
              <div style={{ display: 'flex', gap: '10px' }}>
                 <select className="form-select" value={historyFilter} onChange={(e) => setHistoryFilter(e.target.value)} style={{ padding: '4px 8px' }}>
                   {STATUS_HISTORY.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                 </select>
                 <button className="btn btn-ghost btn-sm" onClick={loadData}><RefreshCw size={14}/></button>
              </div>
            </div>
            {loadReq ? <SkeletonCard /> : myRequests.filter(r => statusMatches(r.Status || r.status, historyFilter)).length === 0 ? <div style={{ padding: 20, textAlign: 'center' }}>No requests found</div> : (
              <div className="table-wrap">
                <table>
                  <thead><tr><th>Type</th><th>Period</th><th>Days</th><th>Status</th><th>Actions</th></tr></thead>
                  <tbody>{myRequests.filter(r => statusMatches(r.Status || r.status, historyFilter)).map((req, i) => <RequestRow key={i} req={req} onAction={handleAction} onEdit={setEditingRequest} isManager={false} />)}</tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {tab === 'all' && isManager && (
          <div className="card">
            <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between' }}>
              <div className="card-title">{isHR ? 'Company-Wide Leaves' : 'Team Pending Approvals'}</div>
              <div style={{ display: 'flex', gap: '10px' }}>
                 <select className="form-select" value={allFilter} onChange={(e) => setAllFilter(e.target.value)} style={{ padding: '4px 8px' }}>
                   {STATUS_OPTIONS.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                 </select>
                 <button className="btn btn-ghost btn-sm" onClick={loadData}><RefreshCw size={14}/></button>
              </div>
            </div>
            {loadAll ? <SkeletonCard /> : allRequests.filter(r => statusMatches(r.Status || r.status, allFilter)).length === 0 ? <div style={{ padding: 20, textAlign: 'center' }}>No requests found</div> : (
              <div className="table-wrap">
                <table>
                  <thead><tr><th>Type</th><th>Employee</th><th>Period</th><th>Days</th><th>Status</th><th>Reason</th><th>Actions</th></tr></thead>
                  <tbody>{allRequests.filter(r => statusMatches(r.Status || r.status, allFilter)).map((req, i) => <RequestRow key={i} req={req} onAction={handleAction} onOverrideClick={setOverrideReq} isManager={true} isHR={isHR} />)}</tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {tab === 'settings' && isHR && (
          <div className="grid-2">
             <div className="card">
               <div className="card-header"><div className="card-title"><ArrowRightLeft size={16} style={{marginRight:6}}/> Payroll Integration</div></div>
               <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: 16 }}>Synchronize all approved leave records with the payroll module to apply unpaid leave deductions.</p>
               <button className="btn btn-primary" onClick={handlePayrollSync}><RefreshCw size={14} style={{marginRight:6}}/> Sync to Payroll</button>
             </div>
             {/* Note: employees list automatically built from allRequests array */}
             <DelegationPanel onDelegate={handleDelegate} employees={uniqueEmployees} />
          </div>
        )}
      </div>
    </>
  );
}
